<?php $adminTitle='LMS Lessons'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ $pdo->prepare('INSERT INTO lms_lessons (module_id,title,lesson_type,content,video_url,resource_url,assignment_instructions,estimated_duration,sort_order,status) VALUES (?,?,?,?,?,?,?,?,?,?)')->execute([(int)$_POST['module_id'],trim($_POST['title']),$_POST['lesson_type'],trim($_POST['content']),trim($_POST['video_url']),trim($_POST['resource_url']),trim($_POST['assignment_instructions']),trim($_POST['estimated_duration']),(int)$_POST['sort_order'],$_POST['status']]); header('Location: lms-lessons.php'); exit; } $modules=$pdo->query('SELECT m.*,c.title course_title FROM lms_modules m JOIN lms_courses c ON c.id=m.course_id ORDER BY c.title,m.sort_order')->fetchAll(); $rows=$pdo->query('SELECT l.*,m.title module_title,c.title course_title FROM lms_lessons l JOIN lms_modules m ON m.id=l.module_id JOIN lms_courses c ON c.id=m.course_id ORDER BY c.title,m.sort_order,l.sort_order')->fetchAll(); ?><h1>Lessons</h1><form class="glass-card mb-4" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><div class="row g-3"><div class="col-md-6"><select class="form-select" name="module_id"><?php foreach($modules as $m): ?><option value="<?= (int)$m['id']; ?>"><?= e($m['course_title'].' / '.$m['title']); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><input class="form-control" name="title" placeholder="Lesson title" required></div><div class="col-md-3"><select class="form-select" name="lesson_type"><option>Text</option><option>Video</option><option>Assignment</option><option>Resource</option></select></div><div class="col-md-3"><input class="form-control" name="estimated_duration" value="20 minutes"></div><div class="col-md-3"><input class="form-control" name="sort_order" value="1"></div><div class="col-md-3"><select class="form-select" name="status"><option>Published</option><option>Draft</option></select></div><div class="col-12"><textarea class="form-control" rows="5" name="content" placeholder="Lesson content" required></textarea></div><div class="col-md-6"><input class="form-control" name="video_url" placeholder="Video URL"></div><div class="col-md-6"><input class="form-control" name="resource_url" placeholder="Downloadable resource URL"></div><div class="col-12"><textarea class="form-control" name="assignment_instructions" placeholder="Assignment instructions"></textarea></div><div class="col-12"><button class="btn btn-premium">Add Lesson</button></div></div></form><div class="glass-card"><table class="table table-dark"><tr><th>Course</th><th>Module</th><th>Lesson</th><th>Type</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['course_title']); ?></td><td><?= e($r['module_title']); ?></td><td><?= e($r['title']); ?></td><td><?= e($r['lesson_type']); ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>